class Solution {
    public:
        int strStr(string haystack, string needle) {
            for(int i = 0, x = 0; i < haystack.length()-1; i++){
                int v = i;
                while(true){
                    if(x >= needle.length())
                        return i;
                    if(haystack[v] != needle[x] || v >= haystack.length())
                        break;
                    v++; x++;

                }
                x = 0;

            }
            return -1;

        }
    };

